/**
 * Main Application Component
 *
 * Sets up routing and global layout for the Mileage Management System.
 */

import { Routes, Route, Navigate } from 'react-router-dom';
import { AppLayout } from './layouts/AppLayout';
import { Dashboard } from './pages/Dashboard';
import { TrainGrid } from './pages/TrainGrid';
import { Assignments } from './pages/Assignments';
import { Planning } from './pages/Planning';
import { Reports } from './pages/Reports';
import { Simulations } from './pages/Simulations';

export function App() {
  return (
    <Routes>
      <Route path="/" element={<AppLayout />}>
        {/* Default route redirects to dashboard */}
        <Route index element={<Navigate to="/dashboard" replace />} />

        {/* Main navigation routes */}
        <Route path="dashboard" element={<Dashboard />} />
        <Route path="fleet" element={<TrainGrid />} />
        <Route path="assignments" element={<Assignments />} />
        <Route path="planning" element={<Planning />} />
        <Route path="reports" element={<Reports />} />
        <Route path="simulations" element={<Simulations />} />

        {/* Catch-all redirect */}
        <Route path="*" element={<Navigate to="/dashboard" replace />} />
      </Route>
    </Routes>
  );
}

/**
 * AppLayout - Main application layout with PatternFly
 *
 * Implements the navigation structure from UX spec MILEAGE-UX-003.
 * Primary navigation: Dashboard | Fleet | Assignments | Planning | Reports | Simulations
 */

import { useState } from 'react';
import { Outlet, useLocation, useNavigate } from 'react-router-dom';
import {
  Page,
  Masthead,
  MastheadBrand,
  MastheadMain,
  MastheadToggle,
  MastheadContent,
  Nav,
  NavItem,
  NavList,
  PageSidebar,
  PageSidebarBody,
  PageToggleButton,
  Brand,
  Toolbar,
  ToolbarContent,
  ToolbarGroup,
  ToolbarItem,
  Button,
  Avatar,
  Dropdown,
  DropdownList,
  DropdownItem,
  MenuToggle,
  NotificationBadge,
  Divider,
} from '@patternfly/react-core';
import {
  BarsIcon,
  BellIcon,
  CogIcon,
  QuestionCircleIcon,
} from '@patternfly/react-icons';

// Navigation items matching RFQ requirements
const NAV_ITEMS = [
  { path: '/dashboard', label: 'Dashboard', description: 'Fleet overview and KPIs' },
  { path: '/fleet', label: 'Fleet Status', description: 'Train mileage grid' },
  { path: '/assignments', label: 'Run Assignments', description: 'Daily train allocation' },
  { path: '/planning', label: 'Planning', description: 'PM scheduling' },
  { path: '/reports', label: 'Reports', description: 'Generate reports' },
  { path: '/simulations', label: 'Simulations', description: 'What-if scenarios' },
];

export function AppLayout() {
  const location = useLocation();
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isUserMenuOpen, setIsUserMenuOpen] = useState(false);
  const [notificationCount] = useState(3); // Mock notification count

  // Toggle sidebar on mobile/tablet
  const onSidebarToggle = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  // Navigation handler
  const onNavSelect = (
    _event: React.FormEvent<HTMLInputElement>,
    result: { itemId: string | number }
  ) => {
    navigate(result.itemId as string);
  };

  // Brand/Logo component
  const headerBrand = (
    <MastheadBrand>
      <Brand
        src="/logo.svg"
        alt="Rolling Stock Mileage Management"
        heights={{ default: '36px' }}
      >
        <span className="pf-v6-u-ml-sm pf-v6-u-font-weight-bold">
          Mileage Management
        </span>
      </Brand>
    </MastheadBrand>
  );

  // User dropdown menu
  const userDropdown = (
    <Dropdown
      isOpen={isUserMenuOpen}
      onSelect={() => setIsUserMenuOpen(false)}
      onOpenChange={setIsUserMenuOpen}
      toggle={(toggleRef) => (
        <MenuToggle
          ref={toggleRef}
          onClick={() => setIsUserMenuOpen(!isUserMenuOpen)}
          isExpanded={isUserMenuOpen}
          variant="plain"
          aria-label="User menu"
        >
          <Avatar src="" alt="User" size="sm" />
        </MenuToggle>
      )}
      popperProps={{ position: 'right' }}
    >
      <DropdownList>
        <DropdownItem key="profile">My Profile</DropdownItem>
        <DropdownItem key="preferences">Preferences</DropdownItem>
        <Divider key="divider" />
        <DropdownItem key="logout">Logout</DropdownItem>
      </DropdownList>
    </Dropdown>
  );

  // Toolbar actions in masthead
  const headerToolbar = (
    <Toolbar id="app-toolbar" isFullHeight isStatic>
      <ToolbarContent>
        <ToolbarGroup
          variant="action-group-plain"
          align={{ default: 'alignEnd' }}
          gap={{ default: 'gapNone', md: 'gapMd' }}
        >
          <ToolbarItem>
            <Button
              aria-label="Notifications"
              variant="plain"
              icon={
                <NotificationBadge
                  variant={notificationCount > 0 ? 'attention' : 'read'}
                  count={notificationCount}
                >
                  <BellIcon />
                </NotificationBadge>
              }
            />
          </ToolbarItem>
          <ToolbarItem>
            <Button
              aria-label="Settings"
              variant="plain"
              icon={<CogIcon />}
            />
          </ToolbarItem>
          <ToolbarItem>
            <Button
              aria-label="Help"
              variant="plain"
              icon={<QuestionCircleIcon />}
            />
          </ToolbarItem>
          <ToolbarItem visibility={{ default: 'hidden', md: 'visible' }}>
            {userDropdown}
          </ToolbarItem>
        </ToolbarGroup>
      </ToolbarContent>
    </Toolbar>
  );

  // Masthead (top header)
  const masthead = (
    <Masthead>
      <MastheadMain>
        <MastheadToggle>
          <PageToggleButton
            variant="plain"
            aria-label="Global navigation"
            isSidebarOpen={isSidebarOpen}
            onSidebarToggle={onSidebarToggle}
          >
            <BarsIcon />
          </PageToggleButton>
        </MastheadToggle>
        {headerBrand}
      </MastheadMain>
      <MastheadContent>{headerToolbar}</MastheadContent>
    </Masthead>
  );

  // Sidebar navigation
  const sidebar = (
    <PageSidebar isSidebarOpen={isSidebarOpen}>
      <PageSidebarBody>
        <Nav
          onSelect={onNavSelect}
          aria-label="Primary navigation"
        >
          <NavList>
            {NAV_ITEMS.map((item) => (
              <NavItem
                key={item.path}
                itemId={item.path}
                isActive={location.pathname === item.path}
                aria-label={item.description}
              >
                {item.label}
              </NavItem>
            ))}
          </NavList>
        </Nav>
      </PageSidebarBody>
    </PageSidebar>
  );

  return (
    <Page masthead={masthead} sidebar={sidebar}>
      <Outlet />
    </Page>
  );
}

/**
 * Mock API Layer for Frontend Development
 *
 * Provides realistic mock data based on RFQ requirements:
 * - 128 trains: 49 Kinki Sharyo + 79 Alstom
 * - PM levels: PM1, PM2, PM3, OVERHAUL
 * - 12-year contract period
 *
 * This mock layer will be replaced with real API calls when backend is ready.
 * The frontend drives the backend - these mocks define the API contract.
 */

import type {
  DailyAssignmentSummary,
  DashboardAlert,
  FleetStatusSummary,
  KPICardData,
  PMTimelineMarker,
  RunAssignmentRow,
} from '../../mileage/types/dashboard';

// Simulate network delay
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Generate realistic KPI data
function generateKPIData(): KPICardData[] {
