      message:
        'AL-067 is 8% above target mileage. Consider reducing daily allocation.',
      timestamp: new Date(now.getTime() - 2 * 60 * 60 * 1000),
      isRead: false,
      isDismissed: false,
      relatedEntities: { trainIds: ['AL-067'] },
      actions: [
        {
          id: 'adjust',
