        },
      ],
    },
    {
      id: 'alert-3',
      severity: 'success',
      category: 'run_assignment',
      title: 'All run assignments set for today',
      message: '24 routes assigned. 121 trains available for service.',
      timestamp: new Date(now.getTime() - 4 * 60 * 60 * 1000),
      isRead: true,
      isDismissed: false,
      actions: [
        {
          id: 'view',
          label: 'View Schedule',
          type: 'secondary',
        },
      ],
    },
    {
      id: 'alert-4',
      severity: 'warning',
      category: 'resource_gap',
      title: 'Resource gap detected in February 2026',
      message: 'Projected 340 man-hour shortage. Consider leveling workload.',
      timestamp: new Date(now.getTime() - 24 * 60 * 60 * 1000),
      isRead: false,
      isDismissed: false,
      actions: [
        {
          id: 'simulate',
          label: 'Run Simulation',
          type: 'primary',
        },
        {
          id: 'view',
          label: 'View Details',
          type: 'secondary',
        },
      ],
    },
    {
      id: 'alert-5',
      severity: 'info',
      category: 'system_notification',
      title: 'Monthly report ready',
