}

// Generate PM timeline markers
function generatePMTimeline(): PMTimelineMarker[] {
  const now = new Date();
  const markers: PMTimelineMarker[] = [];

  // Generate 30 days of scheduled PMs
  const pmData = [
    {
      trainId: 'KS-012',
      level: 'PM1' as const,
      daysFromNow: 2,
      fleet: 'KINKI_SHARYO' as const,
    },
    {
      trainId: 'KS-025',
      level: 'PM2' as const,
      daysFromNow: 7,
      fleet: 'KINKI_SHARYO' as const,
    },
    {
      trainId: 'AL-034',
      level: 'PM1' as const,
      daysFromNow: 14,
      fleet: 'ALSTOM' as const,
    },
    {
      trainId: 'KS-041',
      level: 'PM3' as const,
      daysFromNow: 21,
      fleet: 'KINKI_SHARYO' as const,
    },
    {
      trainId: 'AL-067',
      level: 'OVERHAUL' as const,
      daysFromNow: 28,
      fleet: 'ALSTOM' as const,
    },
    {
      trainId: 'AL-089',
      level: 'PM1' as const,
      daysFromNow: 5,
      fleet: 'ALSTOM' as const,
    },
    {
      trainId: 'KS-033',
      level: 'PM1' as const,
      daysFromNow: 10,
      fleet: 'KINKI_SHARYO' as const,
    },
    {
      trainId: 'AL-045',
      level: 'PM2' as const,
      daysFromNow: 18,
      fleet: 'ALSTOM' as const,
    },
  ];

  pmData.forEach((pm, index) => {
    const scheduledDate = new Date(now);
    scheduledDate.setDate(scheduledDate.getDate() + pm.daysFromNow);

    markers.push({
      id: `pm-${index}`,
      trainId: pm.trainId,
      trainName: pm.trainId,
      fleetType: pm.fleet,
      level: pm.level,
      scheduledDate,
      status: 'scheduled',
      durationHours:
        pm.level === 'OVERHAUL'
          ? 72
          : pm.level === 'PM3'
            ? 24
            : pm.level === 'PM2'
              ? 12
              : 6,
      depot: pm.fleet === 'KINKI_SHARYO' ? 'Depot A' : 'Depot B',
    });
  });

  return markers.sort(
    (a, b) => a.scheduledDate.getTime() - b.scheduledDate.getTime(),
  );
}

// Generate run assignments for today
function generateRunAssignments(): DailyAssignmentSummary {
  const assignments: RunAssignmentRow[] = [
    {
      routeId: 'RT-001',
      routeName: 'Main Line Express',
      trainId: 'KS-005',
      trainName: 'Kinki Sharyo 005',
      fleetType: 'KINKI_SHARYO',
      fitnessStatus: 'FIT',
      estimatedKm: 420,
      status: 'assigned',
      assignedAt: new Date(),
    },
    {
      routeId: 'RT-002',
      routeName: 'Suburban Loop',
      trainId: 'AL-012',
      trainName: 'Alstom 012',
      fleetType: 'ALSTOM',
      fitnessStatus: 'FIT',
      estimatedKm: 385,
      status: 'assigned',
      assignedAt: new Date(),
    },
    {
      routeId: 'RT-003',
      routeName: 'Airport Link',
      trainId: 'KS-018',
      trainName: 'Kinki Sharyo 018',
      fleetType: 'KINKI_SHARYO',
      fitnessStatus: 'RESTRICTED',
      estimatedKm: 280,
      status: 'pending',
      notes: 'Restricted - minor fault',
    },
    {
      routeId: 'RT-004',
      routeName: 'Coast Line',
      trainId: 'AL-045',
      trainName: 'Alstom 045',
      fleetType: 'ALSTOM',
      fitnessStatus: 'FIT',
      estimatedKm: 510,
      status: 'assigned',
      assignedAt: new Date(),
    },
    {
      routeId: 'RT-005',
      routeName: 'City Circle',
      estimatedKm: 445,
      status: 'unassigned',
    },
  ];

  return {
    date: new Date(),
    totalRoutes: assignments.length,
    assignedCount: assignments.filter(a => a.status === 'assigned').length,
    pendingCount: assignments.filter(a => a.status === 'pending').length,
    unassignedCount: assignments.filter(a => a.status === 'unassigned').length,
    conflictCount: 0,
    assignments,
  };
}

// Track dismissed alerts in memory
let dismissedAlertIds = new Set<string>();

/**
 * Mock Dashboard API
 *
 * These functions simulate the API endpoints that the backend will provide.
 * The frontend drives the API contract - backend implements these endpoints.
 */
export const mockDashboardApi = {
  async getKPIData(): Promise<KPICardData[]> {
    await delay(200);
    return generateKPIData();
  },
  async getFleetStatus(): Promise<FleetStatusSummary[]> {
    await delay(150);
    return generateFleetStatus();
  },
  async getAlerts(): Promise<DashboardAlert[]> {
    await delay(100);
    const alerts = generateAlerts();
    return alerts.filter(a => !dismissedAlertIds.has(a.id));
  },
  async getPMTimeline(): Promise<PMTimelineMarker[]> {
    await delay(250);
    return generatePMTimeline();
  },
  async getRunAssignments(): Promise<DailyAssignmentSummary> {
    await delay(200);
    return generateRunAssignments();
  },
  async dismissAlert(alertId: string): Promise<void> {
    await delay(50);
    dismissedAlertIds.add(alertId);
  },
  // Reset mock state (useful for testing)
  resetMockState(): void {
    dismissedAlertIds = new Set();
  },
};

// ============================================================================
// Train Grid Mock API
// ============================================================================

import type {
  FitnessStatus,
  FleetType,
  TrainStatus,
} from '../../mileage/types/train';
import type {
  FleetSummaryCounts,
  PMWindowData,
  TrainGridRow,
} from '../../mileage/types/train-grid';

// Generate realistic 128-train fleet data
function generateTrainGridData(): TrainGridRow[] {
  const trains: TrainGridRow[] = [];
  const now = new Date();

  // Generate 49 Kinki Sharyo trains (KS-001 to KS-049)
  for (let i = 1; i <= 49; i++) {
    trains.push(
      generateTrainRow(
        `KS-${String(i).padStart(3, '0')}`,
        'KINKI_SHARYO',
        i,
        now,
      ),
    );
  }

  // Generate 79 Alstom trains (AL-001 to AL-079)
  for (let i = 1; i <= 79; i++) {
    trains.push(
      generateTrainRow(`AL-${String(i).padStart(3, '0')}`, 'ALSTOM', i, now),
    );
  }

  return trains;
}

function generateTrainRow(
  trainId: string,
  fleetType: FleetType,
  index: number,
  now: Date
): TrainGridRow {
  // PM1 threshold: 50,000 km
  const pm1Threshold = 50000;

  // Randomize mileage between 30,000 and 52,000 km for realistic distribution
  const currentMileage = 30000 + Math.floor(Math.random() * 22000);
  const percentComplete = (currentMileage / pm1Threshold) * 100;

  // Determine status based on percentage
  let pmStatus: 'SAFE' | 'APPROACHING' | 'CRITICAL' | 'OVERDUE';
  if (percentComplete >= 100) pmStatus = 'OVERDUE';
  else if (percentComplete >= 95) pmStatus = 'CRITICAL';
  else if (percentComplete >= 80) pmStatus = 'APPROACHING';
  else pmStatus = 'SAFE';

  // Some trains have issues
  const isCritical = index % 17 === 0;
  const isRestricted = index % 23 === 0;
  const isInMaintenance = index % 31 === 0;
  const isOOS = index % 41 === 0;

  // Calculate days remaining (assuming 400 km/day average)
  const kmRemaining = Math.max(0, pm1Threshold - currentMileage);
  const daysRemaining = Math.ceil(kmRemaining / 400);

  // Fitness status
  let fitnessStatus: FitnessStatus = 'FIT';
  if (isOOS) fitnessStatus = 'UNFIT';
  else if (isRestricted) fitnessStatus = 'RESTRICTED';

  // Train status
  let trainStatus: TrainStatus = 'IN_SERVICE';
  if (isOOS) trainStatus = 'OUT_OF_SERVICE';
  else if (isInMaintenance) trainStatus = 'IN_MAINTENANCE';

  // Last service date (random within last 30 days)
  const lastServiceDays = Math.floor(Math.random() * 30);
  const lastService = new Date(now);
  lastService.setDate(lastService.getDate() - lastServiceDays);

  // Next PM date
  const nextPMDate = new Date(now);
  nextPMDate.setDate(nextPMDate.getDate() + daysRemaining);

  // Random assignment for some trains
  const hasAssignment = Math.random() > 0.3;
  const routeNumber = Math.floor(Math.random() * 24) + 1;

  const pmWindow: PMWindowData = {
    level: 'PM1',
    targetMileage: pm1Threshold,
    currentMileage,
    percentComplete: Math.min(100, percentComplete),
    kmRemaining,
    status: pmStatus,
    daysRemaining,
  };

  return {
    id: trainId,
    trainId,
    name: `Train ${trainId.replace('KS-', '').replace('AL-', '')}`,
    fleetType,
    currentMileage,
    lifetimeMileage: currentMileage + Math.floor(Math.random() * 500000),
    pmWindow,
    fitnessStatus,
    trainStatus,
    nextPM: {
      level: 'PM1',
      daysRemaining,
      estimatedDate: nextPMDate,
    },
    lastService,
    assignment:
      hasAssignment && trainStatus === 'IN_SERVICE' && fitnessStatus !== 'UNFIT'
        ? {
            routeId: `RT-${String(routeNumber).padStart(3, '0')}`,
            routeName: `Route ${routeNumber}`,
            estimatedKm: 300 + Math.floor(Math.random() * 200),
          }
        : undefined,
    baseDepot: fleetType === 'KINKI_SHARYO' ? 'Depot A' : 'Depot B',
    lastUpdated: now,
  };
}

// Cache generated data for consistency within session
let cachedTrainData: TrainGridRow[] | null = null;

export const mockTrainGridApi = {
