// ============================================================================
// Run Assignment Mock API (MILEAGE-UX-005)
// ============================================================================

export interface Route {
  id: string;
  name: string;
  type: 'EXPRESS' | 'LOCAL' | 'SHUTTLE';
  dailyKm: number;
  priority: 'HIGH' | 'MEDIUM' | 'LOW';
  fitnessRequirement: 'FIT' | 'RESTRICTED';
  startTime: string;
  endTime: string;
}

export interface TrainPoolItem {
  trainId: string;
  fleetType: FleetType;
  currentMileage: number;
  fitnessStatus: FitnessStatus;
  pmProgress: number;
  pmDaysRemaining: number;
  score?: number;
}

export interface RouteAssignment {
  routeId: string;
  trainId?: string;
  trainScore?: number;
  status: 'ASSIGNED' | 'AI_SUGGESTED' | 'UNASSIGNED' | 'LOCKED';
  aiRecommendation?: {
    trainId: string;
    score: number;
    reasons: string[];
    alternatives: Array<{
      trainId: string;
      score: number;
      reason: string;
    }>;
  };
}

export interface DailyScheduleData {
  date: Date;
  status: 'DRAFT' | 'PUBLISHED' | 'LOCKED';
  routes: Route[];
  assignments: RouteAssignment[];
  fleetOverview: {
    inService: number;
    inMaintenance: number;
    outOfService: number;
    reserved: number;
  };
  mileageBalance: {
    kinkiSharyo: {
      assigned: number;
      target: number;
    };
    alstom: {
      assigned: number;
      target: number;
    };
    score: number;
  };
  warnings: Array<{
    type: 'PM_APPROACHING' | 'LOW_RESERVE' | 'UNASSIGNED_ROUTES';
    message: string;
    trainIds?: string[];
  }>;
}

// Generate mock routes
function generateRoutes(): Route[] {
  return [
    {
      id: 'RT-001',
      name: 'Express Line A',
      type: 'EXPRESS',
      dailyKm: 450,
      priority: 'HIGH',
      fitnessRequirement: 'FIT',
      startTime: '06:00',
      endTime: '22:00',
    },
    {
      id: 'RT-002',
      name: 'Local Line B',
      type: 'LOCAL',
      dailyKm: 380,
      priority: 'MEDIUM',
      fitnessRequirement: 'FIT',
      startTime: '05:30',
      endTime: '23:00',
    },
    {
      id: 'RT-003',
      name: 'Airport Shuttle',
      type: 'SHUTTLE',
      dailyKm: 280,
      priority: 'HIGH',
      fitnessRequirement: 'FIT',
      startTime: '04:30',
      endTime: '00:00',
    },
    {
      id: 'RT-004',
      name: 'Coast Express',
      type: 'EXPRESS',
      dailyKm: 520,
      priority: 'MEDIUM',
      fitnessRequirement: 'FIT',
      startTime: '06:30',
      endTime: '21:00',
    },
    {
      id: 'RT-005',
      name: 'City Circle',
      type: 'LOCAL',
      dailyKm: 320,
      priority: 'LOW',
      fitnessRequirement: 'RESTRICTED',
      startTime: '07:00',
      endTime: '20:00',
    },
    {
      id: 'RT-006',
      name: 'Metro Connector',
      type: 'LOCAL',
      dailyKm: 290,
      priority: 'MEDIUM',
      fitnessRequirement: 'FIT',
      startTime: '05:00',
      endTime: '23:30',
    },
  ];
}

// Generate train pool
function generateTrainPool(): TrainPoolItem[] {
  const pool: TrainPoolItem[] = [];

  // Add some Kinki Sharyo trains
  for (let i = 1; i <= 20; i++) {
    const mileage = 30000 + Math.floor(Math.random() * 18000);
    const pmProgress = (mileage / 50000) * 100;
    const daysRemaining = Math.ceil((50000 - mileage) / 400);
    const isFit = Math.random() > 0.1;

    pool.push({
      trainId: `KS-${String(i).padStart(3, '0')}`,
      fleetType: 'KINKI_SHARYO',
      currentMileage: mileage,
      fitnessStatus: isFit ? 'FIT' : 'RESTRICTED',
      pmProgress: Math.min(100, pmProgress),
      pmDaysRemaining: Math.max(0, daysRemaining),
    });
  }

  // Add some Alstom trains
  for (let i = 1; i <= 30; i++) {
    const mileage = 28000 + Math.floor(Math.random() * 20000);
    const pmProgress = (mileage / 50000) * 100;
    const daysRemaining = Math.ceil((50000 - mileage) / 400);
    const isFit = Math.random() > 0.08;

    pool.push({
      trainId: `AL-${String(i).padStart(3, '0')}`,
      fleetType: 'ALSTOM',
      currentMileage: mileage,
      fitnessStatus: isFit ? 'FIT' : 'RESTRICTED',
      pmProgress: Math.min(100, pmProgress),
      pmDaysRemaining: Math.max(0, daysRemaining),
    });
  }

  // Sort by mileage (ascending - prefer lower mileage)
  return pool.sort((a, b) => a.currentMileage - b.currentMileage);
}

// Calculate train score for a route
function calculateTrainScore(train: TrainPoolItem, route: Route): number {
  let score = 100;

  // Fitness check (30% weight)
  if (route.fitnessRequirement === 'FIT' && train.fitnessStatus !== 'FIT') {
    return 0; // Cannot assign
  }
  if (train.fitnessStatus === 'FIT') {
    score += 0; // Already at max
  } else {
    score -= 15;
  }

  // Mileage balance (40% weight) - prefer lower mileage
  const mileageScore = Math.max(0, 100 - (train.currentMileage / 50000) * 100);
  score = score * 0.6 + mileageScore * 0.4;

  // PM distance (30% weight) - prefer trains far from PM
  const pmScore = Math.min(100, train.pmDaysRemaining * 3);
  score = score * 0.7 + pmScore * 0.3;

  return Math.round(score);
}

// Generate AI recommendations
function generateAIRecommendations(
  routes: Route[],
  pool: TrainPoolItem[],
): RouteAssignment[] {
  const assignments: RouteAssignment[] = [];
  const usedTrains = new Set<string>();

  // Pre-calculate scores for all train-route combinations
  for (const route of routes) {
    const candidates = pool
      .filter(t => !usedTrains.has(t.trainId))
      .filter(
        t => route.fitnessRequirement !== 'FIT' || t.fitnessStatus === 'FIT',
      )
      .map(t => ({
        train: t,
        score: calculateTrainScore(t, route),
      }))
      .filter(c => c.score > 0)
      .sort((a, b) => b.score - a.score);

    if (candidates.length === 0) {
      assignments.push({
        routeId: route.id,
        status: 'UNASSIGNED',
      });
      continue;
    }

    const best = candidates[0];
    const alternatives = candidates.slice(1, 4).map(c => ({
      trainId: c.train.trainId,
      score: c.score,
      reason:
        c.train.currentMileage > best.train.currentMileage
          ? `Higher mileage (+${(c.train.currentMileage - best.train.currentMileage).toLocaleString()} km)`
          : c.train.fleetType !== best.train.fleetType
            ? 'Different fleet'
            : 'Similar performance',
    }));

    // Generate reasons for the recommendation
    const reasons: string[] = [];
    if (best.train.currentMileage < 40000) {
      reasons.push('Lowest mileage in available pool');
    }
    if (best.train.pmDaysRemaining > 14) {
      reasons.push(`PM1 not due for ${best.train.pmDaysRemaining} days`);
    }
    if (best.train.fitnessStatus === 'FIT') {
      reasons.push('Matches route fitness requirement');
    }

    usedTrains.add(best.train.trainId);

    // Randomly decide if already assigned or AI suggested
    const isAssigned = Math.random() > 0.4;

    assignments.push({
      routeId: route.id,
      trainId: best.train.trainId,
      trainScore: best.score,
      status: isAssigned ? 'ASSIGNED' : 'AI_SUGGESTED',
      aiRecommendation: {
        trainId: best.train.trainId,
        score: best.score,
        reasons,
        alternatives,
      },
    });
  }

  return assignments;
}

// Generate daily schedule
function generateDailySchedule(date: Date): DailyScheduleData {
  const routes = generateRoutes();
  const pool = generateTrainPool();
  const assignments = generateAIRecommendations(routes, pool);

  const assignedCount = assignments.filter(a => a.status === 'ASSIGNED').length;
  const suggestedCount = assignments.filter(
    a => a.status === 'AI_SUGGESTED',
  ).length;
  const unassignedCount = assignments.filter(
    a => a.status === 'UNASSIGNED',
  ).length;

  // Calculate mileage balance
  const kinkiAssigned = assignments
    .filter(a => a.trainId?.startsWith('KS'))
    .reduce((sum, a) => {
      const route = routes.find(r => r.id === a.routeId);
      return sum + (route?.dailyKm || 0);
    }, 0);

  const alstomAssigned = assignments
    .filter(a => a.trainId?.startsWith('AL'))
    .reduce((sum, a) => {
      const route = routes.find(r => r.id === a.routeId);
      return sum + (route?.dailyKm || 0);
    }, 0);

  const warnings: DailyScheduleData['warnings'] = [];

  if (unassignedCount > 0) {
    warnings.push({
      type: 'UNASSIGNED_ROUTES',
      message: `${unassignedCount} routes need assignment`,
    });
  }

  // Check for PM approaching
  const approachingPM = pool.filter(
    t => t.pmDaysRemaining <= 5 && t.pmDaysRemaining > 0,
  );
  if (approachingPM.length > 0) {
    warnings.push({
      type: 'PM_APPROACHING',
      message: `${approachingPM.length} trains approaching PM`,
      trainIds: approachingPM.map(t => t.trainId),
    });
  }

  return {
    date,
    status: assignedCount > 0 && suggestedCount === 0 ? 'PUBLISHED' : 'DRAFT',
    routes,
    assignments,
    fleetOverview: {
      inService: 98,
      inMaintenance: 22,
      outOfService: 8,
      reserved: 0,
    },
    mileageBalance: {
      kinkiSharyo: {
        assigned: kinkiAssigned,
        target: 16000,
      },
      alstom: {
        assigned: alstomAssigned,
        target: 24000,
      },
      score: 87,
    },
    warnings,
  };
}

// Cache for schedule data
let cachedSchedule: DailyScheduleData | null = null;
let cachedPool: TrainPoolItem[] | null = null;

export const mockRunAssignmentApi = {
  async getDailySchedule(date: Date): Promise<DailyScheduleData> {
    await delay(250);
    if (!cachedSchedule) {
      cachedSchedule = generateDailySchedule(date);
    }
    return cachedSchedule;
  },
  async getTrainPool(): Promise<TrainPoolItem[]> {
    await delay(150);
    if (!cachedPool) {
      cachedPool = generateTrainPool();
    }
    return cachedPool;
  },
  async assignTrain(routeId: string, trainId: string): Promise<void> {
    await delay(100);
    if (cachedSchedule) {
      const assignment = cachedSchedule.assignments.find(
        a => a.routeId === routeId,
      );
      if (assignment) {
        assignment.trainId = trainId;
        assignment.status = 'ASSIGNED';
      }
    }
  },
  async acceptRecommendation(routeId: string): Promise<void> {
    await delay(100);
    if (cachedSchedule) {
      const assignment = cachedSchedule.assignments.find(
        a => a.routeId === routeId,
      );
      if (assignment && assignment.aiRecommendation) {
        assignment.trainId = assignment.aiRecommendation.trainId;
        assignment.trainScore = assignment.aiRecommendation.score;
        assignment.status = 'ASSIGNED';
      }
    }
  },
  async acceptAllRecommendations(): Promise<number> {
    await delay(200);
    let count = 0;
    if (cachedSchedule) {
      for (const assignment of cachedSchedule.assignments) {
        if (
          assignment.status === 'AI_SUGGESTED' &&
          assignment.aiRecommendation
        ) {
          assignment.trainId = assignment.aiRecommendation.trainId;
          assignment.trainScore = assignment.aiRecommendation.score;
          assignment.status = 'ASSIGNED';
          count++;
        }
      }
    }
    return count;
  },
  async publishSchedule(): Promise<void> {
    await delay(150);
    if (cachedSchedule) {
      cachedSchedule.status = 'PUBLISHED';
      for (const assignment of cachedSchedule.assignments) {
        if (assignment.status === 'ASSIGNED') {
          assignment.status = 'LOCKED';
        }
      }
    }
  },
  resetCache(): void {
    cachedSchedule = null;
    cachedPool = null;
  },
};

