   287→    sortBy: {
   288→      index: activeSortIndex ?? undefined,
   289→      direction: activeSortDirection,
   290→    },
   291→    onSort: (_event, index, direction) => {
   292→      setActiveSortIndex(index);
   293→      setActiveSortDirection(direction);
   294→    },
   295→    columnIndex,
   296→  });
   297→
   298→  // Selection handlers
   299→  const onSelectAll = (isSelected: boolean) => {
   300→    if (isSelected) {
   301→      setSelectedTrainIds(new Set(paginatedTrains.map(t => t.id)));
   302→    } else {
   303→      setSelectedTrainIds(new Set());
   304→    }
   305→  };
   306→
   307→  const onSelect = (trainId: string, isSelected: boolean) => {
   308→    const newSelected = new Set(selectedTrainIds);
   309→    if (isSelected) {
   310→      newSelected.add(trainId);
   311→    } else {
   312→      newSelected.delete(trainId);
   313→    }
   314→    setSelectedTrainIds(newSelected);
   315→  };
   316→
   317→  // Clear filters
   318→  const clearFilters = () => {
   319→    setFleetFilter('ALL');
   320→    setStatusFilter('ALL');
   321→    setPmDueFilter('ALL');
   322→    setSearchValue('');
   323→    setPage(1);
   324→  };
   325→
   326→  // Format mileage
   327→  const formatMileage = (km: number) => {
   328→    return km.toLocaleString() + ' km';
   329→  };
   330→
   331→  // Format days remaining
   332→  const formatDaysRemaining = (days: number) => {
   333→    if (days <= 0) return 'Overdue';
   334→    if (days === 1) return '1 day';
   335→    if (days < 7) return `${days} days`;
   336→    if (days < 30) return `${Math.ceil(days / 7)} weeks`;
   337→    return `${Math.ceil(days / 30)} months`;
   338→  };
   339→
   340→  // Loading state
   341→  if (isLoading) {
   342→    return (
   343→      <>
   344→        <PageSection variant={PageSectionVariants.light}>
   345→          <Title headingLevel="h1" size="2xl">
   346→            Fleet Status
   347→          </Title>
   348→          <span className="pf-v6-u-font-size-sm pf-v6-u-color-200">
   349→            Loading 128 trains...
   350→          </span>
   351→        </PageSection>
   352→        <PageSection>
   353→          <Card>
   354→            <CardBody>
   355→              <Skeleton height="400px" />
   356→            </CardBody>
   357→          </Card>
   358→        </PageSection>
   359→      </>
   360→    );
   361→  }
   362→
   363→  // Error state
   364→  if (error) {
   365→    return (
   366→      <>
   367→        <PageSection variant={PageSectionVariants.light}>
   368→          <Title headingLevel="h1" size="2xl">
   369→            Fleet Status
   370→          </Title>
   371→        </PageSection>
   372→        <PageSection>
   373→          <Card>
   374→            <CardBody>
   375→              <EmptyState
   376→                variant={EmptyStateVariant.lg}
   377→                icon={ExclamationCircleIcon}
   378→                titleText="Error Loading Fleet Data"
   379→                headingLevel="h2"
   380→              >
   381→                <EmptyStateBody>
   382→                  {error instanceof Error
   383→                    ? error.message
   384→                    : 'Failed to load train data'}
   385→                </EmptyStateBody>
   386→              </EmptyState>
   387→            </CardBody>
   388→          </Card>
   389→        </PageSection>
   390→      </>
   391→    );
   392→  }
   393→
   394→  // Active filters for chips
   395→  const activeFilters: Array<{
   396→    key: string;
   397→    label: string;
   398→    value: string;
   399→  }> = [];
   400→  if (fleetFilter !== 'ALL') {
   401→    activeFilters.push({
   402→      key: 'fleet',
   403→      label: fleetFilter === 'KINKI_SHARYO' ? 'Kinki Sharyo' : 'Alstom',
   404→      value: fleetFilter,
   405→    });
   406→  }
   407→  if (statusFilter !== 'ALL') {
   408→    activeFilters.push({
   409→      key: 'status',
   410→      label: statusFilter,
   411→      value: statusFilter,
   412→    });
   413→  }
   414→  if (pmDueFilter !== 'ALL') {
   415→    const pmLabels: Record<PMDueFilterOption, string> = {
   416→      ALL: 'All',
   417→      OVERDUE: 'Overdue',
   418→      THIS_WEEK: 'Due This Week',
   419→      THIS_MONTH: 'Due This Month',
   420→      NEXT_3_MONTHS: 'Due in 3 Months',
   421→    };
   422→    activeFilters.push({
   423→      key: 'pmDue',
   424→      label: pmLabels[pmDueFilter],
   425→      value: pmDueFilter,
   426→    });
   427→  }
   428→
   429→  return (
   430→    <>
   431→      <PageSection variant={PageSectionVariants.light}>
   432→        <Title headingLevel="h1" size="2xl">
   433→          Fleet Status
   434→        </Title>
   435→        <span className="pf-v6-u-font-size-sm pf-v6-u-color-200">
   436→          {trains.length} trains: 49 Kinki Sharyo + 79 Alstom
   437→        </span>
   438→      </PageSection>
   439→
   440→      <PageSection>
   441→        <Card>
   442→          <CardBody>
   443→            {/* Toolbar with filters */}
   444→            <Toolbar
   445→              clearAllFilters={clearFilters}
   446→              collapseListedFiltersBreakpoint="xl"
   447→            >
   448→              <ToolbarContent>
   449→                {/* Fleet Filter */}
   450→                <ToolbarItem>
   451→                  <Dropdown
   452→                    isOpen={isFleetOpen}
   453→                    onOpenChange={setIsFleetOpen}
   454→                    onSelect={() => setIsFleetOpen(false)}
   455→                    toggle={toggleRef => (
   456→                      <MenuToggle
   457→                        ref={toggleRef}
   458→                        onClick={() => setIsFleetOpen(!isFleetOpen)}
   459→                        isExpanded={isFleetOpen}
   460→                      >
   461→                        Fleet:{' '}
   462→                        {fleetFilter === 'ALL'
   463→                          ? 'All'
   464→                          : fleetFilter === 'KINKI_SHARYO'
   465→                            ? 'Kinki Sharyo'
   466→                            : 'Alstom'}
   467→                      </MenuToggle>
   468→                    )}
   469→                  >
   470→                    <DropdownList>
   471→                      <DropdownItem
   472→                        key="all"
   473→                        onClick={() => setFleetFilter('ALL')}
   474→                      >
   475→                        All Fleets
   476→                      </DropdownItem>
   477→                      <DropdownItem
