   515→                      </DropdownItem>
   516→                      <DropdownItem
   517→                        key="fit"
   518→                        onClick={() => setStatusFilter('FIT')}
   519→                      >
   520→                        FIT
   521→                      </DropdownItem>
   522→                      <DropdownItem
   523→                        key="restricted"
   524→                        onClick={() => setStatusFilter('RESTRICTED')}
   525→                      >
   526→                        RESTRICTED
   527→                      </DropdownItem>
   528→                      <DropdownItem
   529→                        key="unfit"
   530→                        onClick={() => setStatusFilter('UNFIT')}
   531→                      >
   532→                        UNFIT
   533→                      </DropdownItem>
   534→                    </DropdownList>
   535→                  </Dropdown>
   536→                </ToolbarItem>
   537→
   538→                {/* PM Due Filter */}
   539→                <ToolbarItem>
   540→                  <Dropdown
   541→                    isOpen={isPmDueOpen}
   542→                    onOpenChange={setIsPmDueOpen}
   543→                    onSelect={() => setIsPmDueOpen(false)}
   544→                    toggle={toggleRef => (
   545→                      <MenuToggle
