   655→                  </ToolbarItem>
   656→                </ToolbarContent>
   657→              )}
   658→            </Toolbar>
   659→
   660→            {/* Summary Bar */}
   661→            <div className="pf-v6-u-p-md pf-v6-u-background-color-200 pf-v6-u-mb-md">
   662→              <span className="pf-v6-u-mr-lg">
