   699→                  <Th sort={getSortParams(2)} width={10}>
   700→                    Fleet
   701→                  </Th>
   702→                  <Th sort={getSortParams(3)} width={10}>
   703→                    Mileage
   704→                  </Th>
   705→                  <Th sort={getSortParams(4)} width={10}>
   706→                    Fitness
   707→                  </Th>
   708→                  <Th sort={getSortParams(5)} width={20}>
   709→                    PM Window
   710→                  </Th>
   711→                  <Th sort={getSortParams(6)} width={10}>
   712→                    Status
   713→                  </Th>
   714→                  <Th sort={getSortParams(7)} width={10}>
   715→                    Next PM
   716→                  </Th>
   717→                  <Th width={10}>Assignment</Th>
   718→                </Tr>
   719→              </Thead>
   720→              <Tbody>
   721→                {paginatedTrains.map(train => {
   722→                  const pmColors = PM_STATUS_COLORS[train.pmWindow.status];
