   731→                    >
   732→                      <Td
   733→                        select={{
   734→                          rowIndex: 0,
   735→                          onSelect: (_event, isSelected) =>
   736→                            onSelect(train.id, isSelected),
   737→                          isSelected: selectedTrainIds.has(train.id),
   738→                        }}
   739→                      />
   740→                      <Td dataLabel="Train ID">
   741→                        <strong>{train.trainId}</strong>
   742→                      </Td>
   743→                      <Td dataLabel="Name">{train.name}</Td>
   744→                      <Td dataLabel="Fleet">
   745→                        <Label
   746→                          color={
   747→                            train.fleetType === 'KINKI_SHARYO'
   748→                              ? 'blue'
   749→                              : 'purple'
   750→                          }
   751→                        >
   752→                          {train.fleetType === 'KINKI_SHARYO'
   753→                            ? 'Kinki'
   754→                            : 'Alstom'}
   755→                        </Label>
   756→                      </Td>
   757→                      <Td dataLabel="Mileage">
   758→                        {formatMileage(train.currentMileage)}
   759→                      </Td>
   760→                      <Td dataLabel="Fitness">
   761→                        <Label
   762→                          color={fitnessStyle.color as any}
