   773→                            measureLocation={ProgressMeasureLocation.outside}
   774→                            variant={pmColors.variant}
   775→                            size="sm"
   776→                          />
   777→                          <div className="pf-v6-u-font-size-xs pf-v6-u-mt-xs">
   778→                            <Label
   779→                              color={
   780→                                pmColors.variant === 'success'
   781→                                  ? 'green'
   782→                                  : pmColors.variant === 'warning'
   783→                                    ? 'orange'
   784→                                    : 'red'
   785→                              }
   786→                              isCompact
   787→                            >
   788→                              {pmColors.label}
   789→                            </Label>
   790→                            <span className="pf-v6-u-ml-sm">
   791→                              {train.pmWindow.kmRemaining.toLocaleString()} km
   792→                              remaining
   793→                            </span>
   794→                          </div>
   795→                        </div>
   796→                      </Td>
   797→                      <Td dataLabel="Status">
   798→                        <Label color={statusStyle.color as any}>
   799→                          {statusStyle.label}
   800→                        </Label>
   801→                      </Td>
   802→                      <Td dataLabel="Next PM">
   803→                        <div>
