   813→                        ) : (
   814→                          <span className="pf-v6-u-color-200">Unassigned</span>
   815→                        )}
   816→                      </Td>
   817→                    </Tr>
   818→                  );
   819→                })}
   820→              </Tbody>
   821→            </Table>
   822→
   823→            {/* Empty state */}
   824→            {paginatedTrains.length === 0 && (
   825→              <EmptyState
   826→                variant={EmptyStateVariant.sm}
   827→                icon={SearchIcon}
   828→                titleText="No trains found"
   829→                headingLevel="h3"
   830→              >
   831→                <EmptyStateBody>
   832→                  No trains match the current filters. Try adjusting your search
   833→                  criteria.
   834→                </EmptyStateBody>
   835→                <Button variant="link" onClick={clearFilters}>
   836→                  Clear all filters
   837→                </Button>
   838→              </EmptyState>
   839→            )}
   840→
   841→            {/* Pagination */}
   842→            <Pagination
   843→              itemCount={sortedTrains.length}
   844→              perPage={perPage}
