/**
 * Train Grid Page - Fleet Status Grid
 *
 * Implements MILEAGE-UX-004 specification:
 * - 128 trains (49 Kinki Sharyo + 79 Alstom)
 * - PM Window progress bars with status colours
 * - Filtering and sorting
 * - Bulk actions
 */

import {
  Button,
  Card,
  CardBody,
  Dropdown,
  DropdownItem,
  DropdownList,
  EmptyState,
  EmptyStateBody,
  EmptyStateVariant,
  Label,
  LabelGroup,
  MenuToggle,
  PageSection,
  PageSectionVariants,
  Pagination,
  Progress,
  ProgressMeasureLocation,
  SearchInput,
  Skeleton,
  Title,
  Toolbar,
  ToolbarContent,
  ToolbarGroup,
  ToolbarItem,
} from '@patternfly/react-core';
import {
  CheckCircleIcon,
  ExclamationCircleIcon,
  ExclamationTriangleIcon,
  SearchIcon,
} from '@patternfly/react-icons';
import {
  Table,
  Tbody,
  Td,
  Th,
  Thead,
  ThProps,
  Tr,
} from '@patternfly/react-table';
import { useQuery } from '@tanstack/react-query';
import { useMemo, useState } from 'react';
import type {
  FleetFilterOption,
  PMDueFilterOption,
  PMWindowStatus,
  StatusFilterOption,
  TrainGridRow,
} from '../../mileage/types/train-grid';
import { mockTrainGridApi } from '../api/mock';

// PM Window status colours per UX spec
const PM_STATUS_COLORS: Record<
  PMWindowStatus,
  {
    variant: 'success' | 'warning' | 'danger';
    label: string;
  }
> = {
  SAFE: {
    variant: 'success',
    label: 'Safe',
  },
  APPROACHING: {
    variant: 'warning',
    label: 'Approaching',
  },
  CRITICAL: {
    variant: 'danger',
    label: 'Critical',
  },
  OVERDUE: {
    variant: 'danger',
    label: 'Overdue',
  },
};

// Fitness status styling
const FITNESS_STYLES = {
  FIT: {
    color: 'green',
    icon: CheckCircleIcon,
  },
  RESTRICTED: {
    color: 'orange',
    icon: ExclamationTriangleIcon,
  },
  UNFIT: {
    color: 'red',
    icon: ExclamationCircleIcon,
  },
};

// Train status styling
const TRAIN_STATUS_STYLES = {
  IN_SERVICE: {
    color: 'blue',
    label: 'In Service',
  },
  IN_MAINTENANCE: {
    color: 'purple',
    label: 'Maintenance',
  },
  OUT_OF_SERVICE: {
    color: 'grey',
    label: 'OOS',
  },
  RESERVED: {
    color: 'cyan',
    label: 'Reserved',
  },
};

export function TrainGrid() {
  // Filter state
  const [fleetFilter, setFleetFilter] = useState<FleetFilterOption>('ALL');
  const [statusFilter, setStatusFilter] = useState<StatusFilterOption>('ALL');
  const [pmDueFilter, setPmDueFilter] = useState<PMDueFilterOption>('ALL');
  const [searchValue, setSearchValue] = useState('');

  // Dropdown state
  const [isFleetOpen, setIsFleetOpen] = useState(false);
  const [isStatusOpen, setIsStatusOpen] = useState(false);
  const [isPmDueOpen, setIsPmDueOpen] = useState(false);

  // Pagination state
  const [page, setPage] = useState(1);
  const [perPage, setPerPage] = useState(25);

  // Sort state
  const [activeSortIndex, setActiveSortIndex] = useState<number | null>(5); // PM Window column
  const [activeSortDirection, setActiveSortDirection] = useState<
    'asc' | 'desc'
  >('desc');

  // Selection state
  const [selectedTrainIds, setSelectedTrainIds] = useState<Set<string>>(
    new Set(),
  );

  // Fetch train data
  const {
    data: trains = [],
    isLoading,
    error,
  } = useQuery({
    queryKey: ['trains'],
    queryFn: mockTrainGridApi.getTrains,
    staleTime: 5 * 60 * 1000, // 5 minutes
  });

  // Filter trains
  const filteredTrains = useMemo(() => {
    let result = trains;

    // Fleet filter
    if (fleetFilter !== 'ALL') {
      result = result.filter(t => t.fleetType === fleetFilter);
    }

    // Status filter
    if (statusFilter !== 'ALL') {
      result = result.filter(t => t.fitnessStatus === statusFilter);
    }

    // PM Due filter
    if (pmDueFilter !== 'ALL') {
      result = result.filter(t => {
        switch (pmDueFilter) {
          case 'OVERDUE':
            return t.pmWindow.status === 'OVERDUE';
          case 'THIS_WEEK':
            return t.nextPM.daysRemaining <= 7;
          case 'THIS_MONTH':
            return t.nextPM.daysRemaining <= 30;
          case 'NEXT_3_MONTHS':
            return t.nextPM.daysRemaining <= 90;
          default:
            return true;
        }
      });
    }

    // Search filter
    if (searchValue.length >= 2) {
      const search = searchValue.toLowerCase();
      result = result.filter(
        t =>
          t.trainId.toLowerCase().includes(search) ||
          t.name.toLowerCase().includes(search),
      );
    }

    return result;
  }, [
    trains,
    fleetFilter,
    statusFilter,
    pmDueFilter,
    searchValue,
  ]);

  // Sort trains
  const sortedTrains = useMemo(() => {
    if (activeSortIndex === null) return filteredTrains;

    const columnKeys = [
      'trainId',
      'name',
      'fleetType',
      'currentMileage',
      'fitnessStatus',
      'pmWindow',
      'trainStatus',
      'nextPM',
    ];
    const sortKey = columnKeys[activeSortIndex];

    return [...filteredTrains].sort((a, b) => {
      let comparison = 0;

      switch (sortKey) {
        case 'trainId':
        case 'name':
        case 'fleetType':
        case 'fitnessStatus':
        case 'trainStatus':
          comparison = String(a[sortKey as keyof TrainGridRow]).localeCompare(
            String(b[sortKey as keyof TrainGridRow]),
          );
          break;
        case 'currentMileage':
          comparison = a.currentMileage - b.currentMileage;
          break;
        case 'pmWindow':
          comparison = a.pmWindow.percentComplete - b.pmWindow.percentComplete;
          break;
        case 'nextPM':
          comparison = a.nextPM.daysRemaining - b.nextPM.daysRemaining;
          break;
      }

      return activeSortDirection === 'asc' ? comparison : -comparison;
    });
  }, [
    filteredTrains,
    activeSortIndex,
    activeSortDirection,
  ]);

  // Paginate trains
  const paginatedTrains = useMemo(() => {
    const start = (page - 1) * perPage;
    return sortedTrains.slice(start, start + perPage);
  }, [
    sortedTrains,
    page,
    perPage,
  ]);

  // Summary counts
  const summary = useMemo(() => {
    return {
      total: filteredTrains.length,
      fit: filteredTrains.filter(t => t.fitnessStatus === 'FIT').length,
      restricted: filteredTrains.filter(t => t.fitnessStatus === 'RESTRICTED')
        .length,
      unfit: filteredTrains.filter(t => t.fitnessStatus === 'UNFIT').length,
      pmDueThisWeek: filteredTrains.filter(t => t.nextPM.daysRemaining <= 7)
        .length,
    };
  }, [filteredTrains]);

  // Sort handler
  const getSortParams = (columnIndex: number): ThProps['sort'] => ({
    sortBy: {
      index: activeSortIndex ?? undefined,
      direction: activeSortDirection,
    },
    onSort: (_event, index, direction) => {
      setActiveSortIndex(index);
      setActiveSortDirection(direction);
    },
    columnIndex,
  });

  // Selection handlers
  const onSelectAll = (isSelected: boolean) => {
    if (isSelected) {
      setSelectedTrainIds(new Set(paginatedTrains.map(t => t.id)));
    } else {
      setSelectedTrainIds(new Set());
    }
  };

  const onSelect = (trainId: string, isSelected: boolean) => {
    const newSelected = new Set(selectedTrainIds);
    if (isSelected) {
      newSelected.add(trainId);
    } else {
      newSelected.delete(trainId);
    }
    setSelectedTrainIds(newSelected);
  };

  // Clear filters
  const clearFilters = () => {
    setFleetFilter('ALL');
    setStatusFilter('ALL');
    setPmDueFilter('ALL');
    setSearchValue('');
    setPage(1);
  };

  // Format mileage
  const formatMileage = (km: number) => {
    return km.toLocaleString() + ' km';
  };

  // Format days remaining
  const formatDaysRemaining = (days: number) => {
    if (days <= 0) return 'Overdue';
    if (days === 1) return '1 day';
    if (days < 7) return `${days} days`;
    if (days < 30) return `${Math.ceil(days / 7)} weeks`;
    return `${Math.ceil(days / 30)} months`;
  };

  // Loading state
  if (isLoading) {
    return (
      <>
        <PageSection variant={PageSectionVariants.light}>
          <Title headingLevel="h1" size="2xl">
            Fleet Status
          </Title>
          <span className="pf-v6-u-font-size-sm pf-v6-u-color-200">
            Loading 128 trains...
          </span>
        </PageSection>
        <PageSection>
          <Card>
            <CardBody>
              <Skeleton height="400px" />
            </CardBody>
          </Card>
        </PageSection>
      </>
    );
  }

  // Error state
  if (error) {
    return (
      <>
        <PageSection variant={PageSectionVariants.light}>
          <Title headingLevel="h1" size="2xl">
            Fleet Status
          </Title>
        </PageSection>
        <PageSection>
          <Card>
            <CardBody>
              <EmptyState
                variant={EmptyStateVariant.lg}
                icon={ExclamationCircleIcon}
                titleText="Error Loading Fleet Data"
                headingLevel="h2"
              >
                <EmptyStateBody>
                  {error instanceof Error
                    ? error.message
                    : 'Failed to load train data'}
                </EmptyStateBody>
              </EmptyState>
            </CardBody>
          </Card>
        </PageSection>
      </>
    );
  }

  // Active filters for chips
  const activeFilters: Array<{
    key: string;
    label: string;
    value: string;
  }> = [];
  if (fleetFilter !== 'ALL') {
    activeFilters.push({
      key: 'fleet',
      label: fleetFilter === 'KINKI_SHARYO' ? 'Kinki Sharyo' : 'Alstom',
      value: fleetFilter,
    });
  }
  if (statusFilter !== 'ALL') {
    activeFilters.push({
      key: 'status',
      label: statusFilter,
      value: statusFilter,
    });
  }
  if (pmDueFilter !== 'ALL') {
    const pmLabels: Record<PMDueFilterOption, string> = {
      ALL: 'All',
      OVERDUE: 'Overdue',
      THIS_WEEK: 'Due This Week',
      THIS_MONTH: 'Due This Month',
      NEXT_3_MONTHS: 'Due in 3 Months',
    };
    activeFilters.push({
      key: 'pmDue',
      label: pmLabels[pmDueFilter],
      value: pmDueFilter,
    });
  }

  return (
    <>
      <PageSection variant={PageSectionVariants.light}>
        <Title headingLevel="h1" size="2xl">
          Fleet Status
        </Title>
        <span className="pf-v6-u-font-size-sm pf-v6-u-color-200">
          {trains.length} trains: 49 Kinki Sharyo + 79 Alstom
        </span>
      </PageSection>

      <PageSection>
        <Card>
          <CardBody>
            {/* Toolbar with filters */}
            <Toolbar
              clearAllFilters={clearFilters}
              collapseListedFiltersBreakpoint="xl"
            >
              <ToolbarContent>
                {/* Fleet Filter */}
                <ToolbarItem>
                  <Dropdown
                    isOpen={isFleetOpen}
                    onOpenChange={setIsFleetOpen}
                    onSelect={() => setIsFleetOpen(false)}
                    toggle={toggleRef => (
                      <MenuToggle
                        ref={toggleRef}
                        onClick={() => setIsFleetOpen(!isFleetOpen)}
                        isExpanded={isFleetOpen}
                      >
                        Fleet:{' '}
                        {fleetFilter === 'ALL'
                          ? 'All'
                          : fleetFilter === 'KINKI_SHARYO'
                            ? 'Kinki Sharyo'
                            : 'Alstom'}
                      </MenuToggle>
                    )}
                  >
                    <DropdownList>
                      <DropdownItem
                        key="all"
                        onClick={() => setFleetFilter('ALL')}
                      >
                        All Fleets
                      </DropdownItem>
                      <DropdownItem
                        key="kinki"
                        onClick={() => setFleetFilter('KINKI_SHARYO')}
                      >
                        Kinki Sharyo (49)
                      </DropdownItem>
                      <DropdownItem
                        key="alstom"
                        onClick={() => setFleetFilter('ALSTOM')}
                      >
                        Alstom (79)
                      </DropdownItem>
                    </DropdownList>
                  </Dropdown>
                </ToolbarItem>

                {/* Status Filter */}
                <ToolbarItem>
                  <Dropdown
                    isOpen={isStatusOpen}
                    onOpenChange={setIsStatusOpen}
                    onSelect={() => setIsStatusOpen(false)}
                    toggle={toggleRef => (
                      <MenuToggle
                        ref={toggleRef}
                        onClick={() => setIsStatusOpen(!isStatusOpen)}
                        isExpanded={isStatusOpen}
                      >
                        Status: {statusFilter === 'ALL' ? 'All' : statusFilter}
                      </MenuToggle>
                    )}
                  >
                    <DropdownList>
                      <DropdownItem
                        key="all"
                        onClick={() => setStatusFilter('ALL')}
                      >
                        All Statuses
                      </DropdownItem>
                      <DropdownItem
                        key="fit"
                        onClick={() => setStatusFilter('FIT')}
                      >
                        FIT
                      </DropdownItem>
                      <DropdownItem
                        key="restricted"
                        onClick={() => setStatusFilter('RESTRICTED')}
                      >
                        RESTRICTED
                      </DropdownItem>
                      <DropdownItem
                        key="unfit"
                        onClick={() => setStatusFilter('UNFIT')}
                      >
                        UNFIT
                      </DropdownItem>
                    </DropdownList>
                  </Dropdown>
                </ToolbarItem>

                {/* PM Due Filter */}
                <ToolbarItem>
                  <Dropdown
                    isOpen={isPmDueOpen}
                    onOpenChange={setIsPmDueOpen}
                    onSelect={() => setIsPmDueOpen(false)}
                    toggle={toggleRef => (
                      <MenuToggle
                        ref={toggleRef}
                        onClick={() => setIsPmDueOpen(!isPmDueOpen)}
                        isExpanded={isPmDueOpen}
                      >
                        PM Due:{' '}
                        {pmDueFilter === 'ALL'
                          ? 'All'
                          : pmDueFilter.replace('_', ' ')}
                      </MenuToggle>
                    )}
                  >
                    <DropdownList>
                      <DropdownItem
                        key="all"
                        onClick={() => setPmDueFilter('ALL')}
                      >
                        All
                      </DropdownItem>
                      <DropdownItem
                        key="overdue"
                        onClick={() => setPmDueFilter('OVERDUE')}
                      >
                        Overdue
                      </DropdownItem>
                      <DropdownItem
                        key="week"
                        onClick={() => setPmDueFilter('THIS_WEEK')}
                      >
                        This Week
                      </DropdownItem>
                      <DropdownItem
                        key="month"
                        onClick={() => setPmDueFilter('THIS_MONTH')}
                      >
                        This Month
                      </DropdownItem>
                      <DropdownItem
                        key="3months"
                        onClick={() => setPmDueFilter('NEXT_3_MONTHS')}
                      >
                        Next 3 Months
                      </DropdownItem>
                    </DropdownList>
                  </Dropdown>
                </ToolbarItem>

                {/* Search */}
                <ToolbarItem variant="search-filter">
                  <SearchInput
                    placeholder="Search trains..."
                    value={searchValue}
                    onChange={(_event, value) => setSearchValue(value)}
                    onClear={() => setSearchValue('')}
                  />
                </ToolbarItem>

                {/* Bulk actions when selected */}
                {selectedTrainIds.size > 0 && (
                  <ToolbarGroup>
                    <ToolbarItem>
                      <span className="pf-v6-u-mr-sm">
                        {selectedTrainIds.size} selected
                      </span>
                      <Button variant="primary" size="sm">
                        Schedule PM
                      </Button>
                    </ToolbarItem>
                    <ToolbarItem>
                      <Button variant="secondary" size="sm">
                        Export
                      </Button>
                    </ToolbarItem>
                    <ToolbarItem>
                      <Button
                        variant="link"
                        size="sm"
                        onClick={() => setSelectedTrainIds(new Set())}
                      >
                        Clear
                      </Button>
                    </ToolbarItem>
                  </ToolbarGroup>
                )}
              </ToolbarContent>

              {/* Active filter chips */}
              {activeFilters.length > 0 && (
                <ToolbarContent>
                  <ToolbarItem>
                    <LabelGroup categoryName="Active Filters">
                      {activeFilters.map(filter => (
                        <Label
                          key={filter.key}
                          color="blue"
                          onClose={() => {
                            if (filter.key === 'fleet') setFleetFilter('ALL');
                            if (filter.key === 'status') setStatusFilter('ALL');
                            if (filter.key === 'pmDue') setPmDueFilter('ALL');
                          }}
                        >
                          {filter.label}
                        </Label>
                      ))}
                    </LabelGroup>
                  </ToolbarItem>
                  <ToolbarItem>
                    <Button variant="link" onClick={clearFilters}>
                      Clear all filters
                    </Button>
                  </ToolbarItem>
                </ToolbarContent>
              )}
            </Toolbar>

            {/* Summary Bar */}
            <div className="pf-v6-u-p-md pf-v6-u-background-color-200 pf-v6-u-mb-md">
              <span className="pf-v6-u-mr-lg">
                <strong>{summary.total}</strong> trains
              </span>
              <Label color="green" className="pf-v6-u-mr-sm">
                {summary.fit} FIT
              </Label>
              <Label color="orange" className="pf-v6-u-mr-sm">
                {summary.restricted} RESTRICTED
              </Label>
              <Label color="red" className="pf-v6-u-mr-sm">
                {summary.unfit} UNFIT
              </Label>
              {summary.pmDueThisWeek > 0 && (
                <Label color="gold" icon={<ExclamationTriangleIcon />}>
                  {summary.pmDueThisWeek} PM Due This Week
                </Label>
              )}
            </div>

            {/* Data Table */}
            <Table aria-label="Train mileage status grid" variant="compact">
              <Thead>
                <Tr>
                  <Th
                    select={{
                      onSelect: (_event, isSelected) => onSelectAll(isSelected),
                      isSelected:
                        selectedTrainIds.size === paginatedTrains.length &&
                        paginatedTrains.length > 0,
                    }}
                  />
                  <Th sort={getSortParams(0)} width={10}>
                    Train ID
                  </Th>
                  <Th sort={getSortParams(1)} width={10}>
                    Name
                  </Th>
                  <Th sort={getSortParams(2)} width={10}>
                    Fleet
                  </Th>
                  <Th sort={getSortParams(3)} width={10}>
                    Mileage
                  </Th>
                  <Th sort={getSortParams(4)} width={10}>
                    Fitness
                  </Th>
                  <Th sort={getSortParams(5)} width={20}>
                    PM Window
                  </Th>
                  <Th sort={getSortParams(6)} width={10}>
                    Status
                  </Th>
                  <Th sort={getSortParams(7)} width={10}>
                    Next PM
                  </Th>
                  <Th width={10}>Assignment</Th>
                </Tr>
              </Thead>
              <Tbody>
                {paginatedTrains.map(train => {
                  const pmColors = PM_STATUS_COLORS[train.pmWindow.status];
                  const fitnessStyle = FITNESS_STYLES[train.fitnessStatus];
                  const statusStyle = TRAIN_STATUS_STYLES[train.trainStatus];
                  const FitnessIcon = fitnessStyle.icon;

                  return (
                    <Tr
                      key={train.id}
                      isRowSelected={selectedTrainIds.has(train.id)}
                    >
                      <Td
                        select={{
                          rowIndex: 0,
                          onSelect: (_event, isSelected) =>
                            onSelect(train.id, isSelected),
                          isSelected: selectedTrainIds.has(train.id),
                        }}
                      />
                      <Td dataLabel="Train ID">
                        <strong>{train.trainId}</strong>
                      </Td>
                      <Td dataLabel="Name">{train.name}</Td>
                      <Td dataLabel="Fleet">
                        <Label
                          color={
                            train.fleetType === 'KINKI_SHARYO'
                              ? 'blue'
                              : 'purple'
                          }
                        >
                          {train.fleetType === 'KINKI_SHARYO'
                            ? 'Kinki'
                            : 'Alstom'}
                        </Label>
                      </Td>
                      <Td dataLabel="Mileage">
                        {formatMileage(train.currentMileage)}
                      </Td>
                      <Td dataLabel="Fitness">
                        <Label
                          color={fitnessStyle.color as any}
                          icon={<FitnessIcon />}
                        >
                          {train.fitnessStatus}
                        </Label>
                      </Td>
                      <Td dataLabel="PM Window">
                        <div>
                          <Progress
                            value={train.pmWindow.percentComplete}
                            title={`PM1 @ ${train.pmWindow.targetMileage.toLocaleString()} km`}
                            measureLocation={ProgressMeasureLocation.outside}
                            variant={pmColors.variant}
                            size="sm"
                          />
                          <div className="pf-v6-u-font-size-xs pf-v6-u-mt-xs">
                            <Label
                              color={
                                pmColors.variant === 'success'
                                  ? 'green'
                                  : pmColors.variant === 'warning'
                                    ? 'orange'
                                    : 'red'
                              }
                              isCompact
                            >
                              {pmColors.label}
                            </Label>
                            <span className="pf-v6-u-ml-sm">
                              {train.pmWindow.kmRemaining.toLocaleString()} km
                              remaining
                            </span>
                          </div>
                        </div>
                      </Td>
                      <Td dataLabel="Status">
                        <Label color={statusStyle.color as any}>
                          {statusStyle.label}
                        </Label>
                      </Td>
                      <Td dataLabel="Next PM">
                        <div>
                          <strong>{train.nextPM.level}</strong>
                          <div className="pf-v6-u-font-size-xs">
                            {formatDaysRemaining(train.nextPM.daysRemaining)}
                          </div>
                        </div>
                      </Td>
                      <Td dataLabel="Assignment">
                        {train.assignment ? (
                          <span>{train.assignment.routeId}</span>
                        ) : (
                          <span className="pf-v6-u-color-200">Unassigned</span>
                        )}
                      </Td>
                    </Tr>
                  );
                })}
              </Tbody>
            </Table>

            {/* Empty state */}
            {paginatedTrains.length === 0 && (
              <EmptyState
                variant={EmptyStateVariant.sm}
                icon={SearchIcon}
                titleText="No trains found"
                headingLevel="h3"
              >
                <EmptyStateBody>
                  No trains match the current filters. Try adjusting your search
                  criteria.
                </EmptyStateBody>
                <Button variant="link" onClick={clearFilters}>
                  Clear all filters
                </Button>
              </EmptyState>
            )}

            {/* Pagination */}
            <Pagination
              itemCount={sortedTrains.length}
              perPage={perPage}
              page={page}
              onSetPage={(_event, newPage) => setPage(newPage)}
              onPerPageSelect={(_event, newPerPage) => {
                setPerPage(newPerPage);
                setPage(1);
              }}
              perPageOptions={[
                {
                  title: '25',
                  value: 25,
                },
                {
                  title: '50',
                  value: 50,
                },
                {
                  title: '100',
                  value: 100,
                },
              ]}
              variant="bottom"
            />
          </CardBody>
        </Card>
      </PageSection>
    </>
  );
}

