    95→  };
    96→}
    97→
    98→/**
    99→ * Train status for grid display
   100→ */
   101→export interface TrainStatusRow {
   102→  trainId: string;
   103→  name: string;
   104→  fleetType: FleetType;
   105→  currentMileage: number;
   106→  lifetimeMileage: number;
   107→  fitnessStatus: FitnessStatus;
   108→  status: TrainStatus;
   109→  nextPM: {
   110→    level: PMLevel;
   111→    dueDate: Date;
   112→    kmRemaining: number;
   113→    percentToThreshold: number;
   114→  };
   115→  todayAssignment?: {
   116→    routeId: string;
   117→    estimatedKm: number;
   118→    status: 'assigned' | 'pending' | 'unassigned';
   119→  };
   120→  lastServiceDate: Date;
   121→  baseDepot: string;
   122→}
   123→
   124→// ============================================================================
   125→// Alert Types
   126→// ============================================================================
   127→
