   435→/**
   436→ * Determine KPI state based on value and thresholds
   437→ */
   438→export function getKPIState(
   439→  value: number,
   440→  warningThreshold: number,
   441→  criticalThreshold: number,
   442→  invertThresholds = false
   443→): KPIState {
   444→  if (invertThresholds) {
   445→    // Lower is worse (e.g., availability)
   446→    if (value < criticalThreshold) return 'critical';
   447→    if (value < warningThreshold) return 'warning';
   448→    return 'good';
   449→  } else {
   450→    // Higher is worse (e.g., cost variance)
   451→    if (Math.abs(value) > criticalThreshold) return 'critical';
   452→    if (Math.abs(value) > warningThreshold) return 'warning';
   453→    return 'good';
   454→  }
   455→}
   456→
   457→/**
   458→ * Format KPI value for display
   459→ */
   460→export function formatKPIValue(value: number, unit: KPICardData['unit']): string {
   461→  switch (unit) {
   462→    case '%':
   463→      return `${value.toFixed(1)}%`;
   464→    case 'km':
   465→      if (value >= 1000000) return `${(value / 1000000).toFixed(1)}M km`;
   466→      if (value >= 1000) return `${(value / 1000).toFixed(1)}K km`;
   467→      return `${value.toFixed(0)} km`;
   468→    case 'trains':
   469→      return `${value}`;
   470→    case 'hours':
   471→      return `${value.toFixed(0)}h`;
   472→    case 'currency':
   473→      if (Math.abs(value) >= 1000000) return `$${(value / 1000000).toFixed(1)}M`;
   474→      if (Math.abs(value) >= 1000) return `$${(value / 1000).toFixed(1)}K`;
   475→      return `$${value.toFixed(0)}`;
   476→    default:
   477→      return String(value);
   478→  }
   479→}
