   481→/**
   482→ * Get trend direction from value change
   483→ */
   484→export function getTrendDirection(current: number, previous: number): TrendDirection {
   485→  const diff = current - previous;
   486→  if (Math.abs(diff) < 0.001) return 'stable';
   487→  return diff > 0 ? 'up' : 'down';
   488→}
   489→
   490→/**
   491→ * Calculate fleet status distribution percentages
   492→ */
   493→export function calculateStatusPercentages(summary: FleetStatusSummary): {
   494→  fit: number;
   495→  inMaintenance: number;
   496→  outOfService: number;
   497→  restricted: number;
   498→} {
   499→  const total = summary.totalTrains;
   500→  if (total === 0) {
   501→    return { fit: 0, inMaintenance: 0, outOfService: 0, restricted: 0 };
   502→  }
   503→
   504→  return {
   505→    fit: (summary.statusDistribution.fit / total) * 100,
   506→    inMaintenance: (summary.statusDistribution.inMaintenance / total) * 100,
   507→    outOfService: (summary.statusDistribution.outOfService / total) * 100,
   508→    restricted: (summary.statusDistribution.restricted / total) * 100,
   509→  };
   510→}
