/**
 * Train Mileage Grid Types
 *
 * TypeScript types for the train mileage status grid component.
 * Based on UX specification MILEAGE-UX-004.
 */

import type { FleetType, PMLevel, FitnessStatus, TrainStatus } from './train';

// ============================================================================
// Grid Column Types
// ============================================================================

/**
 * Column identifier for the train grid
 */
export type TrainGridColumnId =
  | 'select'
  | 'trainId'
  | 'name'
  | 'fleetType'
  | 'currentMileage'
  | 'pmWindow'
  | 'fitnessStatus'
  | 'trainStatus'
  | 'nextPM'
  | 'lastService'
  | 'assignment'
  | 'actions';

/**
 * Filter type for columns
 */
export type ColumnFilterType =
  | 'text'
  | 'select'
  | 'multiSelect'
  | 'range'
  | 'dateRange';

/**
 * Cell renderer type
 */
export type CellType =
  | 'text'
  | 'number'
  | 'date'
  | 'chip'
  | 'progress'
  | 'actions'
  | 'checkbox';

/**
 * Sticky column position
 */
export type StickyPosition = 'left' | 'right' | null;

/**
 * Column configuration
 */
export interface TrainGridColumn {
  id: TrainGridColumnId;
  header: string;
  width: number;
  minWidth?: number;
  maxWidth?: number;
  sortable: boolean;
  filterable: boolean;
  filterType?: ColumnFilterType;
  filterOptions?: string[];
  cellType?: CellType;
  sticky?: StickyPosition;
  format?: 'number' | 'date' | 'days' | 'percentage';
  visible: boolean;
  order: number;
}

/**
 * Default column configuration
 */
export const DEFAULT_TRAIN_GRID_COLUMNS: TrainGridColumn[] = [
  { id: 'select', header: '', width: 40, sortable: false, filterable: false, cellType: 'checkbox', sticky: 'left', visible: true, order: 0 },
  { id: 'trainId', header: 'Train ID', width: 80, sortable: true, filterable: true, filterType: 'text', sticky: 'left', visible: true, order: 1 },
  { id: 'name', header: 'Name', width: 120, sortable: true, filterable: true, filterType: 'text', visible: true, order: 2 },
  { id: 'fleetType', header: 'Fleet', width: 100, sortable: true, filterable: true, filterType: 'select', filterOptions: ['KINKI_SHARYO', 'ALSTOM'], visible: true, order: 3 },
  { id: 'currentMileage', header: 'Mileage', width: 110, sortable: true, filterable: true, filterType: 'range', format: 'number', visible: true, order: 4 },
  { id: 'pmWindow', header: 'PM Window', width: 150, sortable: true, filterable: true, filterType: 'select', cellType: 'progress', visible: true, order: 5 },
  { id: 'fitnessStatus', header: 'Fitness', width: 100, sortable: true, filterable: true, filterType: 'select', filterOptions: ['FIT', 'RESTRICTED', 'UNFIT'], cellType: 'chip', visible: true, order: 6 },
  { id: 'trainStatus', header: 'Status', width: 110, sortable: true, filterable: true, filterType: 'select', filterOptions: ['IN_SERVICE', 'IN_MAINTENANCE', 'OUT_OF_SERVICE'], cellType: 'chip', visible: true, order: 7 },
  { id: 'nextPM', header: 'Next PM', width: 100, sortable: true, filterable: true, filterType: 'range', format: 'days', visible: true, order: 8 },
  { id: 'lastService', header: 'Last Service', width: 100, sortable: true, filterable: true, filterType: 'dateRange', format: 'date', visible: true, order: 9 },
  { id: 'assignment', header: "Today's Run", width: 120, sortable: false, filterable: true, filterType: 'select', visible: true, order: 10 },
  { id: 'actions', header: '', width: 60, sortable: false, filterable: false, cellType: 'actions', visible: true, order: 11 },
];

// ============================================================================
// PM Window Types
// ============================================================================

/**
 * PM window status based on percentage to threshold
 */
export type PMWindowStatus = 'SAFE' | 'APPROACHING' | 'CRITICAL' | 'OVERDUE';

/**
 * PM window display data
 */
export interface PMWindowData {
  level: PMLevel;
  targetMileage: number;
  currentMileage: number;
  percentComplete: number;
  kmRemaining: number;
  status: PMWindowStatus;
  daysRemaining: number;
}

/**
 * PM window status thresholds (percentage)
 */
export const PM_WINDOW_THRESHOLDS = {
  SAFE: { max: 80 },
  APPROACHING: { min: 80, max: 95 },
  CRITICAL: { min: 95, max: 100 },
  OVERDUE: { min: 100 },
} as const;

/**
 * PM window status colours
 */
export const PM_WINDOW_COLORS: Record<PMWindowStatus, {
  background: string;
  progressBar: string;
  text: string;
}> = {
  SAFE: { background: '#F0FDF4', progressBar: '#22C55E', text: '#166534' },
  APPROACHING: { background: '#FFFBEB', progressBar: '#F59E0B', text: '#92400E' },
  CRITICAL: { background: '#FEF2F2', progressBar: '#EF4444', text: '#991B1B' },
  OVERDUE: { background: '#7F1D1D', progressBar: '#DC2626', text: '#FFFFFF' },
};

// ============================================================================
// Filter Types
// ============================================================================

/**
 * Fleet filter option
 */
export type FleetFilterOption = 'ALL' | FleetType;

/**
 * Status filter option
 */
export type StatusFilterOption = 'ALL' | FitnessStatus;

/**
 * PM due filter option
 */
export type PMDueFilterOption =
  | 'ALL'
  | 'OVERDUE'
  | 'THIS_WEEK'
  | 'THIS_MONTH'
  | 'NEXT_3_MONTHS';

/**
 * Active filter state
 */
export interface TrainGridFilters {
  fleet: FleetFilterOption;
  status: StatusFilterOption;
  pmDue: PMDueFilterOption;
  search: string;
  customFilters?: Record<TrainGridColumnId, unknown>;
}

/**
 * Default filter state
 */
export const DEFAULT_TRAIN_GRID_FILTERS: TrainGridFilters = {
  fleet: 'ALL',
  status: 'ALL',
  pmDue: 'ALL',
  search: '',
};

/**
 * Filter chip for display
 */
export interface FilterChip {
  id: string;
  label: string;
  filterKey: keyof TrainGridFilters;
  value: string;
  removable: boolean;
}

// ============================================================================
// Sorting Types
// ============================================================================

/**
 * Sort direction
 */
export type SortDirection = 'asc' | 'desc' | null;

/**
 * Sort state for a column
 */
export interface ColumnSort {
  columnId: TrainGridColumnId;
  direction: SortDirection;
  priority?: number; // For multi-column sort
}

/**
 * Default sort configuration
 */
export const DEFAULT_SORT: ColumnSort[] = [
  { columnId: 'pmWindow', direction: 'desc', priority: 1 },
];

// ============================================================================
// Pagination Types
// ============================================================================

/**
 * Page size options
 */
export type PageSizeOption = 25 | 50 | 100 | 'all';

/**
 * Pagination state
 */
export interface PaginationState {
  currentPage: number;
  pageSize: PageSizeOption;
  totalItems: number;
  totalPages: number;
}

/**
 * Default pagination
 */
export const DEFAULT_PAGINATION: Omit<PaginationState, 'totalItems' | 'totalPages'> = {
  currentPage: 1,
  pageSize: 25,
};

// ============================================================================
// Selection Types
// ============================================================================

/**
 * Row selection state
 */
export interface SelectionState {
  selectedIds: Set<string>;
  isAllSelected: boolean;
  isAllOnPageSelected: boolean;
}

/**
 * Bulk action type
 */
export type BulkActionType = 'schedule_pm' | 'export' | 'assign' | 'clear';

/**
 * Bulk action configuration
 */
export interface BulkAction {
  id: BulkActionType;
  label: string;
  icon: string;
  requiresConfirmation: boolean;
  minSelection?: number;
  maxSelection?: number;
}

/**
 * Available bulk actions
 */
export const BULK_ACTIONS: BulkAction[] = [
  { id: 'schedule_pm', label: 'Schedule PM', icon: 'calendar', requiresConfirmation: true },
  { id: 'export', label: 'Export', icon: 'download', requiresConfirmation: false },
  { id: 'assign', label: 'Assign Route', icon: 'route', requiresConfirmation: true },
  { id: 'clear', label: 'Clear Selection', icon: 'close', requiresConfirmation: false },
];

// ============================================================================
// Row Action Types
// ============================================================================

/**
 * Row action type
 */
export type RowActionType =
  | 'view_details'
  | 'schedule_pm'
  | 'edit_assignment'
  | 'mileage_history'
  | 'open_maximo';

/**
 * Row action configuration
 */
export interface RowAction {
  id: RowActionType;
  label: string;
  icon: string;
  separator?: boolean;
  requiresPermission?: string;
  disabled?: (row: TrainGridRow) => boolean;
}

/**
 * Available row actions
 */
export const ROW_ACTIONS: RowAction[] = [
  { id: 'view_details', label: 'View Details', icon: 'info' },
  { id: 'schedule_pm', label: 'Schedule PM', icon: 'calendar' },
  { id: 'edit_assignment', label: 'Edit Assignment', icon: 'edit' },
  { id: 'mileage_history', label: 'Mileage History', icon: 'chart' },
  { id: 'open_maximo', label: 'Open in Maximo', icon: 'external_link', separator: true },
];

// ============================================================================
// Grid Row Types
// ============================================================================

/**
 * Train grid row data
 */
export interface TrainGridRow {
  id: string;
  trainId: string;
  name: string;
  fleetType: FleetType;
  currentMileage: number;
  lifetimeMileage: number;
  pmWindow: PMWindowData;
  fitnessStatus: FitnessStatus;
  trainStatus: TrainStatus;
  nextPM: {
    level: PMLevel;
    daysRemaining: number;
    estimatedDate: Date;
  };
  lastService: Date;
  assignment?: {
    routeId: string;
    routeName: string;
    estimatedKm: number;
  };
  baseDepot: string;
  notes?: string;
  lastUpdated: Date;
}

/**
 * Row styling state
 */
export type RowState = 'default' | 'hover' | 'selected' | 'critical';

/**
 * Row styling configuration
 */
export const ROW_STYLES: Record<RowState, {
  background: string;
  borderLeft?: string;
}> = {
  default: { background: '#FFFFFF' },
  hover: { background: '#F3F4F6' },
  selected: { background: '#DBEAFE', borderLeft: '3px solid #3B82F6' },
  critical: { background: '#FEE2E2' },
};

// ============================================================================
// Summary Types
// ============================================================================

/**
 * Fleet summary counts for summary bar
 */
export interface FleetSummaryCounts {
  total: number;
  byFitness: Record<FitnessStatus, number>;
  byStatus: Record<TrainStatus, number>;
  pmDueThisWeek: number;
  pmOverdue: number;
}

// ============================================================================
// Grid State Types
// ============================================================================

/**
 * Complete grid state
 */
export interface TrainGridState {
  // Data
  rows: TrainGridRow[];
  filteredRows: TrainGridRow[];
  isLoading: boolean;
  error?: string;

  // Display
  columns: TrainGridColumn[];
  viewMode: 'table' | 'card';

  // Filtering
  filters: TrainGridFilters;
  activeFilterChips: FilterChip[];

  // Sorting
  sort: ColumnSort[];

  // Pagination
  pagination: PaginationState;

  // Selection
  selection: SelectionState;

  // Summary
  summary: FleetSummaryCounts;

  // Metadata
  lastRefreshed: Date;
  isStale: boolean;
}

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Determine PM window status from percentage
 */
export function getPMWindowStatus(percentComplete: number): PMWindowStatus {
  if (percentComplete >= 100) return 'OVERDUE';
  if (percentComplete >= 95) return 'CRITICAL';
  if (percentComplete >= 80) return 'APPROACHING';
  return 'SAFE';
}

/**
 * Calculate PM window data from train
 */
export function calculatePMWindow(
  currentMileage: number,
  targetMileage: number,
  dailyAverage: number
): PMWindowData {
  const percentComplete = (currentMileage / targetMileage) * 100;
  const kmRemaining = Math.max(0, targetMileage - currentMileage);
  const daysRemaining = dailyAverage > 0 ? Math.ceil(kmRemaining / dailyAverage) : 999;

  return {
    level: 'PM1', // Will be set by caller
    targetMileage,
    currentMileage,
    percentComplete: Math.min(100, percentComplete),
    kmRemaining,
    status: getPMWindowStatus(percentComplete),
    daysRemaining,
  };
}

/**
 * Format mileage for display
 */
export function formatMileage(km: number): string {
  if (km >= 1000) {
    return `${(km / 1000).toFixed(1)}k km`;
  }
  return `${km.toLocaleString()} km`;
}

/**
 * Format days remaining for display
 */
export function formatDaysRemaining(days: number): string {
  if (days <= 0) return 'Overdue';
  if (days === 1) return '1 day';
  if (days < 7) return `${days} days`;
  if (days < 30) return `${Math.ceil(days / 7)} weeks`;
  return `${Math.ceil(days / 30)} months`;
}

/**
 * Get filter chips from current filter state
 */
export function getFilterChips(filters: TrainGridFilters): FilterChip[] {
  const chips: FilterChip[] = [];

  if (filters.fleet !== 'ALL') {
    chips.push({
      id: 'fleet',
      label: filters.fleet === 'KINKI_SHARYO' ? 'Kinki Sharyo' : 'Alstom',
      filterKey: 'fleet',
      value: filters.fleet,
      removable: true,
    });
  }

  if (filters.status !== 'ALL') {
    chips.push({
      id: 'status',
      label: filters.status,
      filterKey: 'status',
      value: filters.status,
      removable: true,
    });
  }

  if (filters.pmDue !== 'ALL') {
    const labels: Record<PMDueFilterOption, string> = {
      ALL: 'All',
      OVERDUE: 'Overdue',
      THIS_WEEK: 'Due This Week',
      THIS_MONTH: 'Due This Month',
      NEXT_3_MONTHS: 'Due in 3 Months',
    };
    chips.push({
      id: 'pmDue',
      label: labels[filters.pmDue],
      filterKey: 'pmDue',
      value: filters.pmDue,
      removable: true,
    });
  }

  if (filters.search) {
    chips.push({
      id: 'search',
      label: `"${filters.search}"`,
      filterKey: 'search',
      value: filters.search,
      removable: true,
    });
  }

  return chips;
}

/**
 * Calculate summary counts from rows
 */
export function calculateSummaryCounts(rows: TrainGridRow[]): FleetSummaryCounts {
  const summary: FleetSummaryCounts = {
    total: rows.length,
    byFitness: { FIT: 0, RESTRICTED: 0, UNFIT: 0 },
    byStatus: { IN_SERVICE: 0, IN_MAINTENANCE: 0, OUT_OF_SERVICE: 0, RESERVED: 0 },
    pmDueThisWeek: 0,
    pmOverdue: 0,
  };

  for (const row of rows) {
    summary.byFitness[row.fitnessStatus]++;
    summary.byStatus[row.trainStatus]++;

    if (row.pmWindow.status === 'OVERDUE') {
      summary.pmOverdue++;
    } else if (row.nextPM.daysRemaining <= 7) {
      summary.pmDueThisWeek++;
    }
  }

  return summary;
}

