/**
 * Train and Fleet Types
 *
 * Core domain types for rolling stock mileage management.
 * Supports 128 trains: 49 Kinki Sharyo + 79 Alstom
 */

/**
 * Fleet manufacturer type
 */
export type FleetType = 'KINKI_SHARYO' | 'ALSTOM';

/**
 * Train fitness status for daily operations
 */
export type FitnessStatus = 'FIT' | 'RESTRICTED' | 'UNFIT';

/**
 * Train operational status
 */
export type TrainStatus = 'IN_SERVICE' | 'IN_MAINTENANCE' | 'OUT_OF_SERVICE' | 'RESERVED';

/**
 * Preventive maintenance levels (mileage-based)
 */
export type PMLevel = 'PM1' | 'PM2' | 'PM3' | 'OVERHAUL';

/**
 * Next PM due information
 */
export interface NextPMDue {
  /** PM level due */
  level: PMLevel;
  /** Mileage threshold when PM is due */
  mileageThreshold: number;
  /** Tolerance window for scheduling flexibility */
  toleranceWindow: {
    /** Minimum mileage (can service early) */
    min: number;
    /** Maximum mileage (must service before) */
    max: number;
  };
  /** Estimated date based on current mileage rate */
  estimatedDate?: Date;
}

/**
 * Train maintenance history entry
 */
export interface MaintenanceHistoryEntry {
  /** Maintenance event ID */
  eventId: string;
  /** PM level performed */
  level: PMLevel;
  /** Date completed */
  completedAt: Date;
  /** Mileage at time of maintenance */
  mileageAtService: number;
  /** Man-hours used */
  manHoursUsed: number;
  /** Total cost */
  totalCost: number;
  /** Notes or issues found */
  notes?: string;
}

/**
 * Train entity
 * Represents a single rolling stock unit
 */
export interface Train {
  /** Unique train identifier (e.g., "KS-001", "AL-001") */
  id: string;

  /** Human-readable name */
  name: string;

  /** Fleet manufacturer type */
  fleetType: FleetType;

  /** Current cumulative mileage (km) since last major overhaul */
  currentMileage: number;

  /** Total lifetime mileage (km) */
  lifetimeMileage: number;

  /** Date of last service */
  lastServiceDate: Date;

  /** Date of last major overhaul */
  lastOverhaulDate: Date;

  /** Next PM due information */
  nextPMDue: NextPMDue;

  /** Current fitness status */
  fitnessStatus: FitnessStatus;

  /** Current operational status */
  status: TrainStatus;

  /** Base depot identifier */
  baseDepot: string;

  /** Year of manufacture */
  yearOfManufacture: number;

  /** Maintenance history */
  maintenanceHistory: MaintenanceHistoryEntry[];

  /** Average daily mileage (computed from history) */
  averageDailyMileage: number;

  /** Notes or special conditions */
  notes?: string;

  /** Created timestamp */
  createdAt: Date;

  /** Last updated timestamp */
  updatedAt: Date;
}

/**
 * Fleet summary statistics
 */
export interface FleetSummary {
  /** Fleet type */
  fleetType: FleetType;

  /** Total number of trains */
  totalTrains: number;

  /** Trains currently fit for service */
  fitTrains: number;

  /** Trains in maintenance */
  inMaintenance: number;

  /** Trains out of service */
  outOfService: number;

  /** Average fleet mileage */
  averageMileage: number;

  /** Mileage variance (spread) */
  mileageVariance: number;

  /** Minimum mileage in fleet */
  minMileage: number;

  /** Maximum mileage in fleet */
  maxMileage: number;

  /** Trains approaching PM due (within tolerance window) */
  approachingPM: number;

  /** Trains overdue for PM */
  overduePM: number;
}

/**
 * Fleet composition with both fleet types
 */
export interface FleetComposition {
  /** Kinki Sharyo fleet summary */
  kinkiSharyo: FleetSummary;

  /** Alstom fleet summary */
  alstom: FleetSummary;

  /** Combined fleet statistics */
  combined: {
    totalTrains: number;
    fitTrains: number;
    inMaintenance: number;
    outOfService: number;
    averageMileage: number;
  };
}

/**
 * Fleet configuration (fixed parameters from RFQ)
 */
export interface FleetConfiguration {
  /** Fleet type */
  fleetType: FleetType;

  /** Number of trains in fleet */
  trainCount: number;

  /** Base depot assignments */
  depots: string[];

  /** Maximum trains in maintenance simultaneously */
  maxSimultaneousMaintenance: number;

  /** Cross-training rate (% of technicians qualified for both fleets) */
  crossTrainingRate: number;

  /** PM interval configuration */
  pmIntervals: {
    level: PMLevel;
    intervalKm: number;
    tolerancePercent: number;
  }[];
}

/**
 * Default fleet configurations per RFQ
 */
export const DEFAULT_FLEET_CONFIGS: Record<FleetType, FleetConfiguration> = {
  KINKI_SHARYO: {
    fleetType: 'KINKI_SHARYO',
    trainCount: 49,
    depots: ['DEPOT_KS_MAIN', 'DEPOT_KS_SECONDARY'],
    maxSimultaneousMaintenance: 5,
    crossTrainingRate: 0.3,
    pmIntervals: [
      { level: 'PM1', intervalKm: 50000, tolerancePercent: 5 },
      { level: 'PM2', intervalKm: 150000, tolerancePercent: 5 },
      { level: 'PM3', intervalKm: 300000, tolerancePercent: 5 },
      { level: 'OVERHAUL', intervalKm: 500000, tolerancePercent: 3 },
    ],
  },
  ALSTOM: {
    fleetType: 'ALSTOM',
    trainCount: 79,
    depots: ['DEPOT_AL_MAIN', 'DEPOT_AL_SECONDARY'],
    maxSimultaneousMaintenance: 8,
    crossTrainingRate: 0.3,
    pmIntervals: [
      { level: 'PM1', intervalKm: 50000, tolerancePercent: 5 },
      { level: 'PM2', intervalKm: 150000, tolerancePercent: 5 },
      { level: 'PM3', intervalKm: 300000, tolerancePercent: 5 },
      { level: 'OVERHAUL', intervalKm: 500000, tolerancePercent: 3 },
    ],
  },
};

/**
 * Helper to generate train ID based on fleet type and index
 */
export function generateTrainId(fleetType: FleetType, index: number): string {
  const prefix = fleetType === 'KINKI_SHARYO' ? 'KS' : 'AL';
  return `${prefix}-${String(index).padStart(3, '0')}`;
}

/**
 * Helper to get fleet type from train ID
 */
export function getFleetTypeFromId(trainId: string): FleetType {
  if (trainId.startsWith('KS-')) return 'KINKI_SHARYO';
  if (trainId.startsWith('AL-')) return 'ALSTOM';
  throw new Error(`Unknown fleet type for train ID: ${trainId}`);
}

/**
 * Default PM intervals (km) per RFQ
 */
export const DEFAULT_PM_INTERVALS: Record<PMLevel, number> = {
  PM1: 50000,
  PM2: 150000,
  PM3: 300000,
  OVERHAUL: 500000,
};

/**
 * PM levels in order of severity
 */
export const PM_LEVELS_ORDER: PMLevel[] = ['PM1', 'PM2', 'PM3', 'OVERHAUL'];

/**
 * Get the next PM level based on current mileage
 */
export function getNextPMLevel(currentMileage: number): PMLevel {
  for (const level of PM_LEVELS_ORDER) {
    const interval = DEFAULT_PM_INTERVALS[level];
    const nextThreshold = Math.ceil(currentMileage / interval) * interval;
    if (nextThreshold > currentMileage) {
      return level;
    }
  }
  return 'PM1'; // Default
}

/**
 * Calculate estimated PM due date based on daily average
 */
export function calculatePMDueDate(
  currentMileage: number,
  pmThreshold: number,
  dailyAverage: number = 400,
  fromDate: Date = new Date()
): Date {
  const mileageRemaining = pmThreshold - currentMileage;
  const daysUntilPM = Math.ceil(mileageRemaining / dailyAverage);
  const dueDate = new Date(fromDate);
  dueDate.setDate(dueDate.getDate() + daysUntilPM);
  return dueDate;
}

/**
 * Helper to calculate next PM due based on current mileage
 */
export function calculateNextPMDue(
  currentMileage: number,
  lastOverhaulMileage: number,
  config: FleetConfiguration
): NextPMDue {
  const mileageSinceOverhaul = currentMileage - lastOverhaulMileage;

  // Find the next PM level due
  for (const pmConfig of config.pmIntervals) {
    const threshold = pmConfig.intervalKm;
    const remainder = mileageSinceOverhaul % threshold;
    const nextThreshold = currentMileage + (threshold - remainder);
    const tolerance = threshold * (pmConfig.tolerancePercent / 100);

    // If within tolerance window, this PM is due soon
    if (remainder >= threshold - tolerance) {
      return {
        level: pmConfig.level,
        mileageThreshold: nextThreshold,
        toleranceWindow: {
          min: nextThreshold - tolerance,
          max: nextThreshold + tolerance,
        },
      };
    }
  }

  // Default to PM1 as the next service
  const pm1Config = config.pmIntervals[0];
  const threshold = pm1Config.intervalKm;
  const remainder = mileageSinceOverhaul % threshold;
  const nextThreshold = currentMileage + (threshold - remainder);
  const tolerance = threshold * (pm1Config.tolerancePercent / 100);

  return {
    level: 'PM1',
    mileageThreshold: nextThreshold,
    toleranceWindow: {
      min: nextThreshold - tolerance,
      max: nextThreshold + tolerance,
    },
  };
}
